prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?parallelGateway ?pgName ?modelName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?mid ;
         bbo:name ?modelName .
  FILTER(?mid = "1ad939eef40c461dafae27f75a0586d3")

  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?def .

  ?parallelGateway a bboExt:ParallelGateway ;
                    tai:belongsTo ?choreo .
  OPTIONAL { ?parallelGateway bbo:name ?pgName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?gw ?gwType ?gwName ?modelName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?mid ;
         bbo:name ?modelName .
  FILTER(?mid = "1ad939eef40c461dafae27f75a0586d3")

  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?def .

  ?gw a ?gwType ;
      tai:belongsTo ?choreo .

  FILTER(
    ?gwType IN (bboExt:ParallelGateway,
                bboExt:ExclusiveGateway,
                bboExt:EventBasedGateway)
  )

  OPTIONAL { ?gw bbo:name ?gwName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?mid ?orgId ?choreo (COUNT(*) AS ?elemCount) WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:normalizedId ?mid .
  FILTER(?mid = "1ad939eef40c461dafae27f75a0586d3")

  ?model tai:belongsTo ?org .
  OPTIONAL { ?org tai:organizationId ?orgId . }

  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?def .

  ?anyElem tai:belongsTo ?choreo .
}
GROUP BY ?model ?modelName ?mid ?orgId ?choreo
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?midNorm ?midOrig ?orgName ?corpusId WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId ?midNorm . }
  OPTIONAL { ?model tai:originalId ?midOrig . }
  FILTER( ?midNorm = "1ad939eef40c461dafae27f75a0586d3" || ?midOrig = "1ad939eef40c461dafae27f75a0586d3" )

  OPTIONAL {
    ?model tai:belongsTo ?org .
    OPTIONAL { ?org tai:organizationId ?orgName . }
  }
  OPTIONAL {
    ?model tai:belongsTo / tai:corpusId ?corpusId .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?gwType ?gw ?name WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1ad939eef40c461dafae27f75a0586d3" ;
         tai:belongsTo / tai:corpusId ?corpusId .

  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?def .

  ?gw a ?gwType ;
      tai:belongsTo ?choreo .
  FILTER(?gwType IN (bboExt:ParallelGateway, bboExt:ExclusiveGateway, bboExt:EventBasedGateway))

  OPTIONAL { ?gw bbo:name ?name . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?containerType ?container ?containerName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1ad939eef40c461dafae27f75a0586d3" ;
         tai:belongsTo / tai:corpusId ?corpusId .

  ?container a ?containerType .
  FILTER(?containerType IN (bboExt:Choreography, bboExt:Collaboration))
  ?container tai:belongsTo / tai:belongsTo ?model .

  OPTIONAL { ?container bbo:name ?containerName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?def ?defType ?defName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1ad939eef40c461dafae27f75a0586d3" .

  ?def tai:belongsTo ?model .
  OPTIONAL { ?def a ?defType . }
  OPTIONAL { ?def bbo:name ?defName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?pg ?pgName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "1ad939eef40c461dafae27f75a0586d3" .

  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def ;
          a bboExt:Choreography .

  ?pg a bboExt:ParallelGateway ;
      tai:belongsTo ?choreo .

  OPTIONAL { ?pg bbo:name ?pgName . }
}
LIMIT 25
